ph:52ed1a897d48_3":{"id":"52ed1a897d48_3","name":"e9d9","__typename":"Paragraph","type":"H3","href":null,"layout":null,"metadata":null,"text":"Introduction","hasDropCap":null,"dropCapImage":null,"markups":[],"iframe":null,"mixtapeMetadata":null},"Paragraph:52ed1a897d48_4":{"id":"52ed1a897d48_4","name":"8bd2","__typename":"Paragraph","type":"P","href":null,"layout":null,"metadata":null,"text":"Continuing from the previous post, Two years in the life of AI, ML, DL and Java, where I had expressed my motivation. I mentioned our discussions, one of the discussions was, that you can write in languages like Python, R, Julia in JuPyteR notebooks. Most were not aware you can also write Java and Scala in addition to Python, SQL etc… with the help of Apache Zeppelin notebooks. And so I did commit to sharing something in those lines to broaden everyone’s awareness. Although it’s been some time since then I have managed to put together my thoughts into this post, showing how we can do similar operations using Apache Zeppelin which supports both Java, and Scala. The project itself is written in Java and it’s open architecture means Zeppelin can support anything as long as an interpreter for that thing has been provided.","hasDropCap":null,"dropCapImage":null,"markups":[{"type":"id","generated":true,"id":"Paragraph:52ed1a897d48_4.markups.0","typename":"Markup"},{"type":"id","generated":true,"id":"Paragraph:52ed1a897d48_4.markups.1","typename":"Markup"},{"type":"id","generated":true,"id":"Paragraph:52ed1a897d48_4.markups.2","typename":"Markup"},{"type":"id","generated":true,"id":"Paragraph:52ed1a897d48_4.markups.3","typename":"Markup"},{"type":"id","generated":true,"id":"Paragraph:52ed1a897d48_4.markups.4","typename":"Markup"},{"type":"id","generated":true,"id":"Paragraph:52ed1a897d48_4.markups.5","typename":"Markup"},{"type":"id","generated":true,"id":"Paragraph:52ed1a897d48_4.markups.6","typename":"Markup"}],"iframe":null,"mixtapeMetadata":null},"Paragraph:52ed1a897d48_4.markups.